B.Zl=new A.ab("A vida n\xe3o examinada n\xe3o vale a pena ser vivida.","S\xf3crates")
B.Y1=new A.ab("S\xf3 sei que nada sei.","S\xf3crates")
B.XR=new A.ab("Conhece-te a ti mesmo.","S\xf3crates")
B.Xr=new A.ab("O segredo da mudan\xe7a \xe9 focar toda a sua energia n\xe3o em lutar contra o velho, mas em construir o novo.","S\xf3crates")
B.XQ=new A.ab("A educa\xe7\xe3o \xe9 acender uma chama, n\xe3o encher um recipiente vazio.","S\xf3crates")
B.XA=new A.ab("Seja a mudan\xe7a que voc\xea deseja ver no mundo interior antes de exigi-la no exterior.","S\xf3crates")
B.XC=new A.ab("A necessidade \xe9 a m\xe3e da inven\xe7\xe3o.","Plat\xe3o")
B.XU=new A.ab("Quem aprende e aprende e n\xe3o pratica o que sabe, \xe9 como quem ara e ara e nunca semeia.","Plat\xe3o")
B.YD=new A.ab("O come\xe7o \xe9 a parte mais importante de qualquer trabalho.","Plat\xe3o")
B.Y3=new A.ab("A opini\xe3o \xe9 a mediadora entre o conhecimento e a ignor\xe2ncia.","Plat\xe3o")
B.YA=new A.ab("Somos o que fazemos repetidamente. Excel\xeancia, ent\xe3o, n\xe3o \xe9 um ato, mas um h\xe1bito.","Arist\xf3teles")
B.Yj=new A.ab("A raiz da educa\xe7\xe3o \xe9 amarga, mas seus frutos s\xe3o doces.","Arist\xf3teles")
B.Yb=new A.ab("A felicidade \xe9 o significado e o prop\xf3sito da vida, o objetivo e o fim da exist\xeancia humana.","Arist\xf3teles")
B.XT=new A.ab("O homem s\xe1bio n\xe3o diz tudo que pensa, mas sempre pensa tudo que diz.","Arist\xf3teles")
B.XP=new A.ab("\xc9 durante os momentos mais dif\xedceis que encontramos a verdadeira medida do car\xe1ter.","Arist\xf3teles")
B.Yi=new A.ab("A virtude \xe9 o meio-termo entre dois extremos, ambos viciosos.","Arist\xf3teles")
B.Z_=new A.ab("Devemos ser donos de nossas pr\xf3prias decis\xf5es, n\xe3o escravos das circunst\xe2ncias.","Arist\xf3teles")
B.XI=new A.ab("Voc\xea tem poder sobre sua mente, n\xe3o sobre os eventos externos. Perceba isso e encontrar\xe1 for\xe7a.","Marco Aur\xe9lio")
B.Z6=new A.ab("A melhor vingan\xe7a \xe9 n\xe3o ser como seu inimigo.","Marco Aur\xe9lio")
B.YQ=new A.ab("Perde seu tempo quem busca a aprova\xe7\xe3o dos outros.","Marco Aur\xe9lio")
B.Xf=new A.ab("Quando voc\xea acorda de manh\xe3, pense no precioso privil\xe9gio de estar vivo: respirar, pensar, desfrutar e amar.","Marco Aur\xe9lio")
B.Xv=new A.ab("A qualidade da sua vida \xe9 determinada pela qualidade dos seus pensamentos.","Marco Aur\xe9lio")
B.YR=new A.ab("Nunca estime algo como lucrativo se te for\xe7ar a quebrar sua palavra ou perder seu autorrespeito.","Marco Aur\xe9lio")
B.Xi=new A.ab("N\xe3o desperdice o resto de sua vida em pensamentos sobre outras pessoas.","Marco Aur\xe9lio")
B.Y0=new A.ab("O homem que faz tudo o que pode dentro das limita\xe7\xf5es que lhe foram impostas faz o suficiente.","Marco Aur\xe9lio")
B.Yt=new A.ab("N\xe3o \xe9 o que acontece com voc\xea, mas como voc\xea reage ao que acontece com voc\xea que importa.","Epicteto")
B.Yg=new A.ab("Fa\xe7a todo o poss\xedvel para n\xe3o depender de circunst\xe2ncias externas.","Epicteto")
B.Yl=new A.ab("N\xe3o procure que as coisas que acontecem sejam como voc\xea quer. Deseje que as coisas que acontecem sejam como s\xe3o e voc\xea encontrar\xe1 tranquilidade.","Epicteto")
B.Xa=new A.ab("Temos dois ouvidos e uma boca para que possamos ouvir duas vezes mais do que falamos.","Epicteto")
B.XH=new A.ab("A riqueza consiste n\xe3o em ter grandes posses, mas em ter poucas necessidades.","Epicteto")
B.Y7=new A.ab("Primeiro diga a si mesmo o que voc\xea ser\xe1; depois fa\xe7a o que tem a fazer.","Epicteto")
B.Zt=new A.ab("N\xe3o \xe9 que tenhamos pouco tempo, mas que desperdi\xe7amos muito.","S\xeaneca")
B.Y2=new A.ab("Enquanto adiamos, a vida passa.","S\xeaneca")
B.XM=new A.ab("\xc9 uma for\xe7a grande n\xe3o precisar de for\xe7a.","S\xeaneca")
B.Yk=new A.ab("Retire-se para dentro de si mesmo tanto quanto puder com aqueles que v\xe3o fazer de voc\xea uma pessoa melhor.","S\xeaneca")
B.Y9=new A.ab("A dificuldade que voc\xea supera hoje \xe9 a sabedoria que voc\xea carrega amanh\xe3.","S\xeaneca")
B.YH=new A.ab("Cuide do corpo para que a mente possa habit\xe1-lo com prazer.","S\xeaneca")
B.XO=new A.ab("Comece. N\xe3o h\xe1 nada que tanto retarde o progresso quanto esperar por ele.","S\xeaneca")
B.XV=new A.ab("Viva com os seres humanos como se Deus te visse; fale com Deus como se os seres humanos te ouvissem.","S\xeaneca")
B.Y_=new A.ab("A mudan\xe7a \xe9 a \xfanica constante da vida.","Her\xe1clito")
B.YF=new A.ab("N\xe3o \xe9 poss\xedvel pisar duas vezes no mesmo rio.","Her\xe1clito")
B.YP=new A.ab("O car\xe1ter \xe9 o destino.","Her\xe1clito")
B.YB=new A.ab("Muito aprender n\xe3o ensina a ter bom senso.","Her\xe1clito")
B.XG=new A.ab("A jornada de mil milhas come\xe7a com um \xfanico passo.","Lao Tzu")
B.Z4=new A.ab("Aquele que se conhece \xe9 s\xe1bio. Aquele que conquista os outros \xe9 forte. Aquele que conquista a si mesmo \xe9 poderoso.","Lao Tzu")
B.Xh=new A.ab("A natureza n\xe3o tem pressa, mas realiza tudo.","Lao Tzu")
B.YO=new A.ab("Quando eu deixo de ser o que sou, torno-me o que poderia ser.","Lao Tzu")
B.YJ=new A.ab("Seja cuidadoso com seus pensamentos, eles se tornam suas palavras. Seja cuidadoso com suas palavras, elas se tornam suas a\xe7\xf5es.","Lao Tzu")
B.Xu=new A.ab("Agir sem expectativa, realizar sem fazer alarde \u2014 isso \xe9 a virtude suprema.","Lao Tzu")
B.Xl=new A.ab("N\xe3o importa qu\xe3o devagar voc\xea v\xe1, desde que n\xe3o pare.","Conf\xfacio")
B.X9=new A.ab("Fazer o bem por obriga\xe7\xe3o \xe9 virtude; fazer o bem por amor \xe9 sabedoria.","Conf\xfacio")
B.Xt=new A.ab("A pessoa que move uma montanha come\xe7a carregando pequenas pedras.","Conf\xfacio")
B.Yw=new A.ab("Escolha um trabalho que voc\xea ame e n\xe3o ter\xe1 que trabalhar um \xfanico dia em sua vida.","Conf\xfacio")
B.Z3=new A.ab("Antes de se aventurar a melhorar o mundo, d\xea tr\xeas voltas em torno de sua pr\xf3pria casa.","Conf\xfacio")
B.YI=new A.ab("Aquele que aprende mas n\xe3o pensa est\xe1 perdido. Aquele que pensa mas n\xe3o aprende est\xe1 em grande perigo.","Conf\xfacio")
B.Yy=new A.ab("O que voc\xea pensa, voc\xea se torna. O que voc\xea sente, voc\xea atrai. O que voc\xea imagina, voc\xea cria.","Buda")
B.Xp=new A.ab("A mente \xe9 tudo. O que voc\xea pensa, voc\xea se torna.","Buda")
B.Zq=new A.ab("Tr\xeas coisas n\xe3o podem ser escondidas por muito tempo: o sol, a lua e a verdade.","Buda")
B.Yh=new A.ab("N\xe3o viva no passado, n\xe3o sonhe com o futuro, concentre a mente no momento presente.","Buda")
B.Zw=new A.ab("A paz vem de dentro. N\xe3o a procure fora.","Buda")
B.YC=new A.ab("Voc\xea mesmo, mais do que qualquer outra pessoa no universo, merece seu amor e afeto.","Buda")
B.Xg=new A.ab("O que n\xe3o me mata, me fortalece.","Friedrich Nietzsche")
B.Xx=new A.ab("Aquele que tem um porqu\xea para viver suporta quase qualquer como.","Friedrich Nietzsche")
B.Z8=new A.ab("A grandeza do homem est\xe1 em ser uma ponte, n\xe3o um fim.","Friedrich Nietzsche")
B.Z1=new A.ab("Sem m\xfasica a vida seria um erro.","Friedrich Nietzsche")
B.Zz=new A.ab("Torne-se quem voc\xea \xe9.","Friedrich Nietzsche")
B.Zg=new A.ab("Aquele que luta com monstros deve tomar cuidado para n\xe3o se tornar um monstro.","Friedrich Nietzsche")
B.Yf=new A.ab("Penso, logo existo.","Ren\xe9 Descartes")
B.Zu=new A.ab("Divida cada dificuldade em tantas partes quanto for necess\xe1rio para resolv\xea-la.","Ren\xe9 Descartes")
B.XD=new A.ab("Age de tal forma que a m\xe1xima de tua vontade possa valer como princ\xedpio de uma legisla\xe7\xe3o universal.","Immanuel Kant")
B.Xs=new A.ab("Duas coisas me enchem de admira\xe7\xe3o: o c\xe9u estrelado acima de mim e a lei moral dentro de mim.","Immanuel Kant")
B.Z5=new A.ab("Aja apenas segundo uma m\xe1xima tal que possa ao mesmo tempo querer que ela se torne uma lei universal.","Immanuel Kant")
B.Xb=new A.ab("O homem est\xe1 condenado a ser livre.","Jean-Paul Sartre")
B.Ym=new A.ab("A exist\xeancia precede a ess\xeancia.","Jean-Paul Sartre")
B.Zb=new A.ab("A vida n\xe3o tem sentido a priori. Antes de voc\xea viv\xea-la, ela n\xe3o \xe9 nada; cabe a voc\xea dar-lhe um sentido.","Jean-Paul Sartre")
B.Xq=new A.ab("\xc9 preciso imaginar S\xedsifo feliz.","Albert Camus")
B.Yp=new A.ab("No meio do inverno aprendi, finalmente, que havia em mim um ver\xe3o invenc\xedvel.","Albert Camus")
B.Zo=new A.ab("A rebeldia \xe9 um dos \xfanicos atos humanos coerentes.","Albert Camus")
B.XE=new A.ab("O talento acerta alvos que ningu\xe9m mais pode acertar; o g\xeanio acerta alvos que ningu\xe9m mais pode ver.","Arthur Schopenhauer")
B.Zf=new A.ab("Riqueza \xe9 como a \xe1gua do mar: quanto mais voc\xea bebe, mais sede tem.","Arthur Schopenhauer")
B.XJ=new A.ab("A paz n\xe3o \xe9 aus\xeancia de guerra; \xe9 uma virtude, um estado de esp\xedrito, uma disposi\xe7\xe3o para a benevol\xeancia, confian\xe7a e justi\xe7a.","Baruch Spinoza")
B.Yo=new A.ab("O desejo \xe9 a pr\xf3pria ess\xeancia do homem.","Baruch Spinoza")
B.Zn=new A.ab("A imagina\xe7\xe3o \xe9 mais importante que o conhecimento.","Albert Einstein")
B.Zm=new A.ab("No meio de toda dificuldade h\xe1 uma oportunidade.","Albert Einstein")
B.Y6=new A.ab("A mente que se abre a uma nova ideia jamais voltar\xe1 ao seu tamanho original.","Albert Einstein")
B.Ya=new A.ab("Insanidade \xe9 continuar fazendo a mesma coisa esperando resultados diferentes.","Albert Einstein")
B.XF=new A.ab("A vida \xe9 como andar de bicicleta: para manter o equil\xedbrio \xe9 preciso continuar em movimento.","Albert Einstein")
B.Xn=new A.ab("Aprenda as regras do jogo. E depois jogue melhor do que ningu\xe9m.","Albert Einstein")
B.Za=new A.ab("Conhece o inimigo e conhece a ti mesmo; em cem batalhas nunca correr\xe1s perigo.","Sun Tzu")
B.YM=new A.ab("Oportunidades se multiplicam quando s\xe3o aproveitadas.","Sun Tzu")
B.YG=new A.ab("A vit\xf3ria suprema \xe9 vencer sem combater.","Sun Tzu")
B.YS=new A.ab("Em meio ao caos existe tamb\xe9m oportunidade.","Sun Tzu")
B.XW=new A.ab("Viva como se fosse morrer amanh\xe3. Aprenda como se fosse viver para sempre.","Mahatma Gandhi")
B.Ys=new A.ab("Seja a mudan\xe7a que voc\xea deseja ver no mundo.","Mahatma Gandhi")
B.Zp=new A.ab("A for\xe7a n\xe3o vem da capacidade f\xedsica. Vem de uma vontade indom\xe1vel.","Mahatma Gandhi")
B.Xy=new A.ab("Primeiro eles te ignoram, depois riem de voc\xea, depois lutam contra voc\xea. Ent\xe3o voc\xea vence.","Mahatma Gandhi")
B.Xk=new A.ab("A maior gl\xf3ria em viver n\xe3o est\xe1 em nunca cair, mas em se levantar sempre que ca\xedmos.","Nelson Mandela")
B.Zc=new A.ab("Tudo parece imposs\xedvel at\xe9 que seja feito.","Nelson Mandela")
B.XN=new A.ab("A educa\xe7\xe3o \xe9 a arma mais poderosa que voc\xea pode usar para mudar o mundo.","Nelson Mandela")
B.Zs=new A.ab("O sucesso \xe9 trope\xe7ar de fracasso em fracasso sem perder o entusiasmo.","Winston Churchill")
B.Z0=new A.ab("Se voc\xea est\xe1 passando pelo inferno, continue andando.","Winston Churchill")
B.Xo=new A.ab("Atitude \xe9 uma pequena coisa que faz uma grande diferen\xe7a.","Winston Churchill")
B.YY=new A.ab("A melhor maneira de prever o futuro \xe9 cri\xe1-lo.","Abraham Lincoln")
B.Xe=new A.ab("D\xea-me seis horas para cortar uma \xe1rvore e passarei as primeiras quatro afiando o machado.","Abraham Lincoln")
B.Z2=new A.ab("A \xfanica maneira de fazer um \xf3timo trabalho \xe9 amar o que voc\xea faz.","Steve Jobs")
B.Ye=new A.ab("Sua vis\xe3o de mundo j\xe1 est\xe1 moldada antes de voc\xea perceber que tem uma. A vida \xe9 curta demais para viver a dos outros.","Steve Jobs")
B.Zv=new A.ab("Fique com fome. Fique tolo.","Steve Jobs")
B.YN=new A.ab("O tempo que voc\xea gosta de perder n\xe3o \xe9 tempo perdido.","Bertrand Russell")
B.Zh=new A.ab("A conquista da felicidade n\xe3o \xe9 algo que acontece \u2014 \xe9 algo que voc\xea constr\xf3i.","Bertrand Russell")
B.Zd=new A.ab("O segredo da felicidade \xe9 muito simples: encontre o que te interessa genuinamente e fa\xe7a isso.","Bertrand Russell")
